import{_ as o,o as t,c as a,ae as r}from"./chunks/framework.DTQlDYOH.js";const p=JSON.parse('{"title":"Reference: Top-level structure","description":"","frontmatter":{},"headers":[],"relativePath":"reference/overview.md","filePath":"reference/overview.md"}'),n={name:"reference/overview.md"};function s(i,e,d,l,c,h){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="reference-top-level-structure" tabindex="-1">Reference: Top-level structure <a class="header-anchor" href="#reference-top-level-structure" aria-label="Permalink to &quot;Reference: Top-level structure&quot;">​</a></h1><p>A B.A.G.E.L. game is a single JSON object. These are the top-level keys.</p><h2 id="entities" tabindex="-1">entities <a class="header-anchor" href="#entities" aria-label="Permalink to &quot;entities&quot;">​</a></h2><p>Array of entity definitions: boards, pieces, cards, etc.</p><ul><li><strong>name</strong> — Identifier used in <code>sharedBoard</code>, <code>personalBoard</code>, conditions, and moves.</li><li><strong>type</strong> — <code>&quot;Grid&quot;</code> or <code>&quot;Space&quot;</code>. Omit for generic pieces/cards.</li><li><strong>width</strong> / <strong>height</strong> — For <code>type: &quot;Grid&quot;</code>, the grid dimensions.</li><li><strong>perPlayer</strong> — If <code>true</code>, one copy of the entity (or set) per player (e.g. hand, score).</li><li><strong>count</strong> — Number of instances (e.g. <code>12</code> for checkers, <code>&quot;Infinity&quot;</code> for unbounded).</li><li><strong>state</strong> — Default state (e.g. <code>isKing: false</code> or <code>player: &quot;0&quot;</code>).</li><li><strong>displayProperties</strong> — List of property names to show in the UI (e.g. <code>[&quot;value&quot;, &quot;suit&quot;]</code> for cards).</li><li><strong>contentsHiddenFrom</strong> — <code>&quot;All&quot;</code> or <code>&quot;Others&quot;</code> for hidden containers (e.g. hand).</li></ul><p>The engine also injects built-in entities: a <code>Space</code> type, a <code>sharedBoard</code> board, and a per-player <code>playerMarker</code> entity.</p><h2 id="sharedboard-personalboard" tabindex="-1">sharedBoard / personalBoard <a class="header-anchor" href="#sharedboard-personalboard" aria-label="Permalink to &quot;sharedBoard / personalBoard&quot;">​</a></h2><ul><li><strong>sharedBoard</strong> — Array of entity matchers (e.g. name <code>mainGrid</code>) that form the shared board. Defaults to all entities if omitted.</li><li><strong>personalBoard</strong> — Optional. Array of entity matchers that form each player’s personal board (e.g. hand, score). Creates a per-player board and places those entities there at setup.</li></ul><h2 id="initialplacements" tabindex="-1">initialPlacements <a class="header-anchor" href="#initialplacements" aria-label="Permalink to &quot;initialPlacements&quot;">​</a></h2><p>Optional array of placement objects (each with <strong>entity</strong> and <strong>destination</strong>) to place entities at setup. The engine converts these into internal <code>initialMoves</code>. Use <strong>destination</strong> with <code>name</code> (e.g. <code>mainGrid</code>) or <code>index</code> for a specific space.</p><h2 id="players" tabindex="-1">Players <a class="header-anchor" href="#players" aria-label="Permalink to &quot;Players&quot;">​</a></h2><ul><li><strong>numPlayers</strong> — Shorthand: sets both <code>minPlayers</code> and <code>maxPlayers</code>.</li><li><strong>minPlayers</strong> / <strong>maxPlayers</strong> — Allowed player count range.</li></ul><h2 id="turn" tabindex="-1">turn <a class="header-anchor" href="#turn" aria-label="Permalink to &quot;turn&quot;">​</a></h2><ul><li><strong>minMoves</strong> / <strong>maxMoves</strong> — Moves per turn (default when omitted: 1 and 1).</li><li><strong>activePlayers</strong> — Optional. Maps current player to a stage (e.g. currentPlayer → <code>&quot;jumpIfPossible&quot;</code>).</li><li><strong>stages</strong> — Optional. Map of stage names to objects with <strong>initialMoves</strong> and <strong>moves</strong>. Used for multi-stage turns (e.g. checkers: jump if possible → move → king pieces).</li></ul><h2 id="moves" tabindex="-1">moves <a class="header-anchor" href="#moves" aria-label="Permalink to &quot;moves&quot;">​</a></h2><p>Object mapping move names to move definitions. Each definition has:</p><ul><li><strong>type</strong> — One of: <code>PlaceNew</code>, <code>MoveEntity</code>, <code>RemoveEntity</code>, <code>TakeFrom</code>, <code>SetState</code>, <code>SetActivePlayers</code>, <code>EndTurn</code>, <code>PassTurn</code>, <code>ForEach</code>, <code>Pass</code>, <code>Shuffle</code>.</li><li><strong>arguments</strong> — Depends on the move type (e.g. <code>entity</code>, <code>destination</code>).</li><li><strong>then</strong> — Optional array of automatic follow-up move rules after a successful move.</li></ul><p>See <a href="./moves.html">Moves</a> for details.</p><h2 id="endif" tabindex="-1">endIf <a class="header-anchor" href="#endif" aria-label="Permalink to &quot;endIf&quot;">​</a></h2><p>Array of end scenarios. Each item:</p><ul><li><strong>conditions</strong> — Array of condition objects. All must be satisfied.</li><li><strong>result</strong> — Outcome when conditions are met (e.g. <strong>winner</strong> or <strong>draw: true</strong>). Values can use <a href="./values-and-refs.html">value resolution</a> (e.g. contextPath, expression).</li></ul><p>Legacy key <strong>endConditions</strong> is normalized to <strong>endIf</strong> by the engine.</p><h2 id="initialmoves" tabindex="-1">initialMoves <a class="header-anchor" href="#initialmoves" aria-label="Permalink to &quot;initialMoves&quot;">​</a></h2><p>Optional array of move rules run once at game setup (after boards and initial placements). Used for things like dealing cards into hands.</p><h2 id="phases" tabindex="-1">phases <a class="header-anchor" href="#phases" aria-label="Permalink to &quot;phases&quot;">​</a></h2><p>Optional. Map of phase names to phase config (each can have <code>turn</code>, <code>moves</code>, <code>initialMoves</code>, <code>endIf</code>, <code>next</code>). For multi-phase games.</p>',26)])])}const g=o(n,[["render",s]]);export{p as __pageData,g as default};
